UPDATE LINE
SET remaining_data = remaining_data - #{deductAmount},
    updated_at = NOW()
WHERE line_id = #{lineId}
  AND deleted_at IS NULL
  AND remaining_data >= #{deductAmount}

UPDATE FAMILY
SET pool_remaining_data = pool_remaining_data - #{deductAmount},
    updated_at = NOW()
WHERE family_id = #{familyId}
  AND deleted_at IS NULL
  AND pool_remaining_data >= #{deductAmount}
